prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?node ?nodeName WHERE {
  ?node tai:belongsTo <https://www.teamingai-project.eu/kg/process/qualityInspection/sid_d8d3781e_3b5a_4864_8c2e_da05b5b75a2b> .
  ?node ((^bbo:has_sourceRef)/bbo:has_targetRef)+ ?node .
